// ── Engine.java ──────────────────────────────────────────────
public class Engine {

    private long window;
    private static final int WIDTH  = 800;
    private static final int HEIGHT = 600;

    public void init() {

        // 1. Install error handler before anything else
        GLFWErrorCallback.createPrint(System.err).set();

        // 2. Initialize GLFW
        if (!glfwInit())
            throw new IllegalStateException("GLFW init failed");

        // 3-7. Configure window hints BEFORE createWindow
        glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3);
        glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3);
        glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);
        glfwWindowHint(GLFW_VISIBLE,   GLFW_FALSE); // hidden until positioned
        glfwWindowHint(GLFW_RESIZABLE, GLFW_TRUE);

        // 8. Create window + context
        window = glfwCreateWindow(WIDTH, HEIGHT, "MyEngine", NULL, NULL);
        if (window == NULL)
            throw new RuntimeException("Window creation failed");

        // 10-12. Register callbacks
        glfwSetKeyCallback(window, (win, key, scancode, action, mods) -> {
            if (key == GLFW_KEY_ESCAPE && action == GLFW_PRESS)
                glfwSetWindowShouldClose(win, true);
        });

        glfwSetFramebufferSizeCallback(window, (win, w, h) ->
            glViewport(0, 0, w, h)      // keep viewport in sync with window
        );

        // 13-14. Centre window on primary monitor
        GLFWVidMode vm = glfwGetVideoMode(glfwGetPrimaryMonitor());
        glfwSetWindowPos(window,
            (vm.width()  - WIDTH)  / 2,
            (vm.height() - HEIGHT) / 2);

        // 15. Make context current — REQUIRED before any GL call
        glfwMakeContextCurrent(window);

        // 16. VSync ON
        glfwSwapInterval(1);

        // 17. Show window now that everything is ready
        glfwShowWindow(window);

        // → Phase 2 starts here: GL.createCapabilities()
    }
}

