public void init() {

    // ... Phase 1 window creation above ...

    // 1. Load all OpenGL function pointers for this context
    //    MUST be the very first GL call — nothing else works before this
    GL.createCapabilities();

    // 2-3. Log driver info — verify version matches hints
    System.out.println("OpenGL : " + glGetString(GL_VERSION));
    System.out.println("GLSL   : " + glGetString(GL_SHADING_LANGUAGE_VERSION));
    System.out.println("GPU    : " + glGetString(GL_RENDERER));

    // 4. Define the render region inside the window
    glViewport(0, 0, WIDTH, HEIGHT);

    // 5. Set the background color (dark grey)
    glClearColor(0.1f, 0.1f, 0.1f, 1.0f);

    // 6-7. Depth testing — required for correct 3D occlusion
    glEnable(GL_DEPTH_TEST);
    glDepthFunc(GL_LESS);       // pass if closer than stored depth

    // 8-10. Back-face culling — skip hidden triangle faces
    glEnable(GL_CULL_FACE);
    glCullFace(GL_BACK);        // discard back-facing triangles
    glFrontFace(GL_CCW);        // CCW winding = front face (standard)

    // 11. Explicit fill mode — easy to toggle to GL_LINE for wireframe
    glPolygonMode(GL_FRONT_AND_BACK, GL_FILL);

    // → Phase 3 starts here: compile shaders
    // → Phase 4 starts here: upload mesh data
    // → Phase 5 starts here: load textures
}

