// ── ShaderProgram.java ───────────────────────────────────────
public class ShaderProgram {

    private final int programID;

    // Cached uniform locations — queried once after linking
    private int modelLoc;
    private int viewLoc;
    private int projectionLoc;

    public ShaderProgram(String vertPath, String fragPath) throws IOException {

        // 1-2. Load GLSL source from disk
        String vertSrc = Files.readString(Path.of(vertPath));
        String fragSrc = Files.readString(Path.of(fragPath));

        // 3-7. Compile vertex shader
        int vertID = compileShader(GL_VERTEX_SHADER,   vertSrc);

        // 8-12. Compile fragment shader
        int fragID = compileShader(GL_FRAGMENT_SHADER, fragSrc);

        // 13. Create program and link
        programID = glCreateProgram();
        glAttachShader(programID, vertID);      // 14
        glAttachShader(programID, fragID);      // 15
        glLinkProgram(programID);               // 16

        // 17-18. Check link status
        if (glGetProgrami(programID, GL_LINK_STATUS) == GL_FALSE) {
            System.err.println(glGetProgramInfoLog(programID));
            throw new RuntimeException("Shader link failed: " + vertPath);
        }

        // 19-22. Detach and delete shader objects — program keeps the binary
        glDetachShader(programID, vertID);
        glDetachShader(programID, fragID);
        glDeleteShader(vertID);
        glDeleteShader(fragID);

        // 23. Activate program then cache all uniform locations
        glUseProgram(programID);
        modelLoc      = glGetUniformLocation(programID, "uModel");
        viewLoc       = glGetUniformLocation(programID, "uView");
        projectionLoc = glGetUniformLocation(programID, "uProjection");

        // Warn on missing uniforms — -1 means unused or typo in name
        if (modelLoc == -1) System.err.println("WARN: uModel not found");
    }

    // ── Reusable compile helper ──────────────────────────────
    private int compileShader(int type, String src) {
        int id = glCreateShader(type);
        glShaderSource(id, src);
        glCompileShader(id);

        if (glGetShaderi(id, GL_COMPILE_STATUS) == GL_FALSE) {
            System.err.println(glGetShaderInfoLog(id));
            glDeleteShader(id);
            throw new RuntimeException("Shader compile failed");
        }
        return id;
    }

    // ── API used by Engine render loop ───────────────────────
    public void bind()   { glUseProgram(programID); }
    public void unbind() { glUseProgram(0); }

    public void setMatrix4f(int location, Matrix4f mat, FloatBuffer buf) {
        glUniformMatrix4fv(location, false, mat.get(buf));
    }

    public int getModelLoc()      { return modelLoc; }
    public int getViewLoc()       { return viewLoc; }
    public int getProjectionLoc() { return projectionLoc; }

    public void delete() { glDeleteProgram(programID); }
}

