// ── Mesh.java ─────────────────────────────────────────────────
public class Mesh {

    private final int vao;
    private final int vbo;
    private final int ebo;
    private final int indexCount;

    // Vertex layout: [ x, y, z,  u, v,  nx, ny, nz ]
    //                 pos(3)  uv(2)  normal(3)  → stride = 8 floats
    private static final int STRIDE = 8 * Float.BYTES;

    public Mesh(float[] vertices, int[] indices) {

        indexCount = indices.length;

        // 3-4. Generate and bind VAO first — records everything below
        vao = glGenVertexArrays();
        glBindVertexArray(vao);

        // 5-8. Upload vertex data into VBO
        vbo = glGenBuffers();
        glBindBuffer(GL_ARRAY_BUFFER, vbo);
        glBufferData(GL_ARRAY_BUFFER,
            BufferUtils.createFloatBuffer(vertices.length)
                       .put(vertices).flip(),
            GL_STATIC_DRAW);

        // 9-12. Upload index data into EBO
        ebo = glGenBuffers();
        glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, ebo);
        glBufferData(GL_ELEMENT_ARRAY_BUFFER,
            BufferUtils.createIntBuffer(indices.length)
                       .put(indices).flip(),
            GL_STATIC_DRAW);

        // 13-14. Attribute 0 — position (vec3, offset 0)
        glVertexAttribPointer(0, 3, GL_FLOAT, false, STRIDE, 0L);
        glEnableVertexAttribArray(0);

        // 15-16. Attribute 1 — UV coords (vec2, offset 12 bytes)
        glVertexAttribPointer(1, 2, GL_FLOAT, false, STRIDE, 3L * Float.BYTES);
        glEnableVertexAttribArray(1);

        // 17-18. Attribute 2 — normals (vec3, offset 20 bytes)
        glVertexAttribPointer(2, 3, GL_FLOAT, false, STRIDE, 5L * Float.BYTES);
        glEnableVertexAttribArray(2);

        // 19-20. Unbind VAO then VBO — seals recorded state
        glBindVertexArray(0);
        glBindBuffer(GL_ARRAY_BUFFER, 0);
        // NOTE: do NOT unbind EBO while VAO is unbound —
        //       the EBO binding lives inside the VAO
    }

    // ── Called once per draw call in the render loop ─────────
    public void draw() {
        glBindVertexArray(vao);
        glDrawElements(GL_TRIANGLES, indexCount, GL_UNSIGNED_INT, 0L);
        glBindVertexArray(0);
    }

    // ── Called during engine shutdown ─────────────────────────
    public void delete() {
        glDeleteVertexArrays(vao);
        glDeleteBuffers(vbo);
        glDeleteBuffers(ebo);
    }
}

