// ── Texture.java ──────────────────────────────────────────────
public class Texture {

    private final int textureID;

    public Texture(String filePath) {

        // 1. Flip Y axis once before loading — OpenGL UV origin is bottom-left
        STBImage.stbi_set_flip_vertically_on_load(true);

        // 2. Allocate output buffers for image dimensions
        IntBuffer w  = BufferUtils.createIntBuffer(1);
        IntBuffer h  = BufferUtils.createIntBuffer(1);
        IntBuffer ch = BufferUtils.createIntBuffer(1);

        // 3. Load image — force 4 channels (RGBA) for consistent upload
        ByteBuffer pixels = STBImage.stbi_load(filePath, w, h, ch, 4);

        // 4. Fail fast with a readable error message
        if (pixels == null)
            throw new RuntimeException("Failed to load texture: " + filePath
                + " — " + STBImage.stbi_failure_reason());

        // 5. Generate texture handle
        textureID = glGenTextures();

        // 6-7. Select texture unit 0 and bind
        glActiveTexture(GL_TEXTURE0);
        glBindTexture(GL_TEXTURE_2D, textureID);

        // 8-11. Sampling parameters — set BEFORE glTexImage2D
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S,     GL_REPEAT);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T,     GL_REPEAT);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR_MIPMAP_LINEAR);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);

        // 12. Upload pixel data to GPU
        //     w.get(0) / h.get(0) read the dimensions stbi_load wrote
        glTexImage2D(GL_TEXTURE_2D,
            0,              // mipmap level 0 = base
            GL_RGBA,        // internal GPU format
            w.get(0),       // image width  (from stbi_load)
            h.get(0),       // image height (from stbi_load)
            0,              // border — always 0 in core profile
            GL_RGBA,        // source pixel format
            GL_UNSIGNED_BYTE,
            pixels);

        // 13. Auto-generate all mipmap levels from base image
        glGenerateMipmap(GL_TEXTURE_2D);

        // 14. Free CPU pixel buffer immediately — GPU has the data now
        STBImage.stbi_image_free(pixels);

        // 15. Unbind — clean state after setup
        glBindTexture(GL_TEXTURE_2D, 0);
    }

    // ── Called before each draw call in the render loop ───────
    // unit: GL_TEXTURE0, GL_TEXTURE1, etc.
    public void bind(int unit) {
        glActiveTexture(unit);
        glBindTexture(GL_TEXTURE_2D, textureID);
    }

    public void unbind() {
        glBindTexture(GL_TEXTURE_2D, 0);
    }

    // ── Called during engine shutdown ─────────────────────────
    public void delete() {
        glDeleteTextures(textureID);
    }

    public int getID() { return textureID; }
}

