// ── Camera.java ───────────────────────────────────────────────
public class Camera {

    // Camera state
    private Vector3f position;
    private Vector3f front;
    private Vector3f up;

    // Euler angles (degrees)
    private float yaw   = -90.0f; // -90 points down -Z on init
    private float pitch =   0.0f;

    // Settings
    private float speed       = 5.0f;
    private float sensitivity = 0.1f;
    private float fov         = 45.0f;

    // Reusable matrices — pre-allocated, never newed inside render loop
    private final Matrix4f viewMatrix       = new Matrix4f();
    private final Matrix4f projectionMatrix = new Matrix4f();

    // Reusable upload buffer
    private final FloatBuffer matrixBuffer = BufferUtils.createFloatBuffer(16);

    public Camera(float x, float y, float z) {
        position = new Vector3f(x, y, z);
        front    = new Vector3f(0.0f, 0.0f, -1.0f);
        up       = new Vector3f(0.0f, 1.0f,  0.0f);
    }

    // ── Called once or on window resize ───────────────────────
    public void buildProjection(float aspectRatio) {
        projectionMatrix.identity()
            .perspective(
                (float) Math.toRadians(fov), // FOV in radians
                aspectRatio,                 // width / height
                0.1f,                        // near plane
                100.0f);                     // far plane
    }

    // ── Called every frame — update input then rebuild view ───
    public void update(long window, float deltaTime) {

        // WASD movement — scale by deltaTime for frame-rate independence
        float step = speed * deltaTime;
        if (glfwGetKey(window, GLFW_KEY_W) == GLFW_PRESS)
            position.add(new Vector3f(front).mul(step));
        if (glfwGetKey(window, GLFW_KEY_S) == GLFW_PRESS)
            position.sub(new Vector3f(front).mul(step));
        if (glfwGetKey(window, GLFW_KEY_A) == GLFW_PRESS)
            position.sub(new Vector3f(front).cross(up).normalize().mul(step));
        if (glfwGetKey(window, GLFW_KEY_D) == GLFW_PRESS)
            position.add(new Vector3f(front).cross(up).normalize().mul(step));
    }

    // ── Called from mouse callback (registered in Phase 1) ────
    public void processMouseMovement(float dx, float dy) {
        yaw   += dx * sensitivity;
        pitch  = Math.clamp(pitch - dy * sensitivity, -89.0f, 89.0f);

        // Rebuild front vector from updated yaw and pitch
        front.x = (float)(Math.cos(Math.toRadians(yaw)) * Math.cos(Math.toRadians(pitch)));
        front.y = (float)(Math.sin(Math.toRadians(pitch)));
        front.z = (float)(Math.sin(Math.toRadians(yaw)) * Math.cos(Math.toRadians(pitch)));
        front.normalize();
    }

    // ── Returns rebuilt view matrix — called each frame ───────
    public Matrix4f getViewMatrix() {
        return viewMatrix.identity()
            .lookAt(position,
                    new Vector3f(position).add(front), // target = pos + front
                    up);
    }

    // ── Upload all three matrices to shader ───────────────────
    public void uploadMatrices(int viewLoc, int projLoc) {
        glUniformMatrix4fv(viewLoc, false, getViewMatrix().get(matrixBuffer));
        glUniformMatrix4fv(projLoc, false, projectionMatrix.get(matrixBuffer));
    }

    public FloatBuffer getMatrixBuffer() { return matrixBuffer; }
}

