// ── UniformManager.java ───────────────────────────────────────
public class UniformManager {

    private final int programID;

    // Cached locations — queried once after linking, reused every frame
    private final Map<String, Integer> locationCache = new HashMap<>();

    // Reusable matrix upload buffer
    private final FloatBuffer matrixBuffer = BufferUtils.createFloatBuffer(16);

    public UniformManager(int programID) {
        this.programID = programID;
    }

    // ── Call once after glLinkProgram ─────────────────────────
    //    Caches all locations — never call glGetUniformLocation
    //    inside the render loop
    public void cacheLocation(String name) {
        int loc = glGetUniformLocation(programID, name);
        if (loc == -1)
            System.err.println("WARN: uniform '" + name + "' not found or inactive");
        locationCache.put(name, loc);
    }

    private int loc(String name) {
        return locationCache.getOrDefault(name, -1);
    }

    // ── Uniform setters — used inside render loop ─────────────

    public void setMatrix4f(String name, Matrix4f mat) {
        int location = loc(name);
        if (location != -1)
            glUniformMatrix4fv(location, false, mat.get(matrixBuffer));
    }

    public void setMatrix3f(String name, Matrix3f mat) {
        int location = loc(name);
        FloatBuffer buf = BufferUtils.createFloatBuffer(9);
        if (location != -1)
            glUniformMatrix3fv(location, false, mat.get(buf));
    }

    public void setInt(String name, int value) {
        int location = loc(name);
        if (location != -1) glUniform1i(location, value);
    }

    public void setFloat(String name, float value) {
        int location = loc(name);
        if (location != -1) glUniform1f(location, value);
    }

    public void setVec2(String name, float x, float y) {
        int location = loc(name);
        if (location != -1) glUniform2f(location, x, y);
    }

    public void setVec3(String name, float x, float y, float z) {
        int location = loc(name);
        if (location != -1) glUniform3f(location, x, y, z);
    }

    public void setVec4(String name, float x, float y, float z, float w) {
        int location = loc(name);
        if (location != -1) glUniform4f(location, x, y, z, w);
    }
}

