// ── Engine.java → renderLoop() ───────────────────────────────
public void renderLoop() {

    // Pre-loop baseline time
    double lastFrameTime = glfwGetTime();

    while (!glfwWindowShouldClose(window)) {

        // ── 1. FRAME TIMING ───────────────────────────────────
        double currentTime = glfwGetTime();
        float  deltaTime   = (float)(currentTime - lastFrameTime);
        lastFrameTime      = currentTime;

        // ── 2. PROCESS EVENTS ─────────────────────────────────
        // Updates keyboard/mouse state — must come before input reads
        glfwPollEvents();

        // ── 3. UPDATE LOGIC ───────────────────────────────────
        camera.update(window, deltaTime);   // WASD + mouse look
        // physicsSystem.update(deltaTime); // game logic goes here

        // ── 4. CLEAR BUFFERS ──────────────────────────────────
        // Always clear both — forgetting depth causes z-fighting
        glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT);

        // ── 5. ACTIVATE SHADER ────────────────────────────────
        shader.bind();

        // ── 6. UPLOAD FRAME-LEVEL UNIFORMS ────────────────────
        // View and projection are the same for all objects this frame
        uniforms.setMatrix4f("uView",       camera.getViewMatrix());
        uniforms.setMatrix4f("uProjection", projectionMatrix);
        uniforms.setVec3("uLightPos",       1.2f, 1.0f, 2.0f);
        uniforms.setFloat("uTime",          (float) glfwGetTime());

        // ── 7. OPAQUE DRAW PASS ───────────────────────────────
        for (GameObject obj : opaqueObjects) {

            // Build model matrix fresh each frame — TRS order
            model.identity()
                 .translate(obj.position)
                 .rotate((float) Math.toRadians(obj.rotation), 0, 1, 0)
                 .scale(obj.scale);

            // Upload per-object uniforms
            uniforms.setMatrix4f("uModel", model);

            // Bind texture to unit 0
            obj.texture.bind(GL_TEXTURE0);

            // Bind geometry and draw
            obj.mesh.draw(); // → glBindVertexArray + glDrawElements
        }

        // ── 8. TRANSPARENT DRAW PASS ──────────────────────────
        glEnable(GL_BLEND);
        glBlendFunc(GL_SRC_ALPHA, GL_ONE_MINUS_SRC_ALPHA);
        glDepthMask(false); // test depth but do not write it

        // Sort back-to-front before drawing
        transparentObjects.sort((a, b) -> Float.compare(
            b.position.distance(camera.getPosition()),
            a.position.distance(camera.getPosition())));

        for (GameObject obj : transparentObjects) {
            model.identity()
                 .translate(obj.position)
                 .scale(obj.scale);
            uniforms.setMatrix4f("uModel", model);
            obj.texture.bind(GL_TEXTURE0);
            obj.mesh.draw();
        }

        // Restore state after transparent pass
        glDepthMask(true);
        glDisable(GL_BLEND);

        // ── 9. PRESENT FRAME ──────────────────────────────────
        // Swap AFTER all draw calls — never mid-frame
        glfwSwapBuffers(window);
    }
    // → render loop exits here
    // → Engine.java → cleanup() is called next (Phase 11)
}

// ── Main entry point ─────────────────────────────────────────
public static void main(String[] args) {
    Engine engine = new Engine();
    engine.init();        // Phases 1-7
    engine.renderLoop();  // Phase 8
    engine.cleanup();     // Phase 11
}

