// ── Framebuffer.java ──────────────────────────────────────────
public class Framebuffer {

    private final int fbo;
    private final int colorTexture;
    private final int rbo;
    private final int quadVao;
    private final int quadVbo;

    public Framebuffer(int width, int height) {

        // ── 2-9. Color attachment texture ─────────────────────
        colorTexture = glGenTextures();
        glBindTexture(GL_TEXTURE_2D, colorTexture);
        glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA,
            width, height, 0,
            GL_RGBA, GL_UNSIGNED_BYTE, (ByteBuffer) null); // null = empty
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_CLAMP_TO_EDGE);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_CLAMP_TO_EDGE);
        glBindTexture(GL_TEXTURE_2D, 0);

        // ── 10-13. Depth + stencil renderbuffer ───────────────
        rbo = glGenRenderbuffers();
        glBindRenderbuffer(GL_RENDERBUFFER, rbo);
        glRenderbufferStorage(GL_RENDERBUFFER, GL_DEPTH24_STENCIL8, width, height);
        glBindRenderbuffer(GL_RENDERBUFFER, 0);

        // ── 14-18. Assemble FBO ───────────────────────────────
        fbo = glGenFramebuffers();
        glBindFramebuffer(GL_FRAMEBUFFER, fbo);

        glFramebufferTexture2D(GL_FRAMEBUFFER,
            GL_COLOR_ATTACHMENT0, GL_TEXTURE_2D, colorTexture, 0);

        glFramebufferRenderbuffer(GL_FRAMEBUFFER,
            GL_DEPTH_STENCIL_ATTACHMENT, GL_RENDERBUFFER, rbo);

        // Always validate — undefined behaviour if incomplete
        if (glCheckFramebufferStatus(GL_FRAMEBUFFER) != GL_FRAMEBUFFER_COMPLETE)
            throw new RuntimeException("Framebuffer is not complete!");

        // 19. Restore screen framebuffer
        glBindFramebuffer(GL_FRAMEBUFFER, 0);

        // ── Full-screen quad (NDC, 2 triangles) ───────────────
        // layout: [ x, y,   u, v ] per vertex
        float[] quadVerts = {
            -1f,  1f,  0f, 1f,
            -1f, -1f,  0f, 0f,
             1f, -1f,  1f, 0f,
            -1f,  1f,  0f, 1f,
             1f, -1f,  1f, 0f,
             1f,  1f,  1f, 1f
        };
        quadVao = glGenVertexArrays();
        quadVbo = glGenBuffers();
        glBindVertexArray(quadVao);
        glBindBuffer(GL_ARRAY_BUFFER, quadVbo);
        glBufferData(GL_ARRAY_BUFFER,
            BufferUtils.createFloatBuffer(quadVerts.length).put(quadVerts).flip(),
            GL_STATIC_DRAW);
        // position (vec2) at location 0
        glVertexAttribPointer(0, 2, GL_FLOAT, false, 4 * Float.BYTES, 0L);
        glEnableVertexAttribArray(0);
        // UV (vec2) at location 1
        glVertexAttribPointer(1, 2, GL_FLOAT, false, 4 * Float.BYTES, 2L * Float.BYTES);
        glEnableVertexAttribArray(1);
        glBindVertexArray(0);
    }

    // ── PASS 1: bind FBO — scene renders into colorTexture ────
    public void bindForRendering() {
        glBindFramebuffer(GL_FRAMEBUFFER, fbo);
        glEnable(GL_DEPTH_TEST);
        glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT);
    }

    // ── PASS 2: restore screen — draw quad with post-process ──
    public void drawToScreen(int postProcessShaderID) {
        glBindFramebuffer(GL_FRAMEBUFFER, 0);   // back to screen
        glDisable(GL_DEPTH_TEST);               // quad needs no depth
        glClear(GL_COLOR_BUFFER_BIT);

        glUseProgram(postProcessShaderID);
        glActiveTexture(GL_TEXTURE0);
        glBindTexture(GL_TEXTURE_2D, colorTexture); // FBO output → shader input
        glUniform1i(glGetUniformLocation(postProcessShaderID, "uScreenTexture"), 0);

        glBindVertexArray(quadVao);
        glDrawArrays(GL_TRIANGLES, 0, 6);       // full-screen quad
        glBindVertexArray(0);

        glEnable(GL_DEPTH_TEST);                // restore for next frame
    }

    public void delete() {
        glDeleteFramebuffers(fbo);
        glDeleteTextures(colorTexture);
        glDeleteRenderbuffers(rbo);
        glDeleteBuffers(quadVbo);
        glDeleteVertexArrays(quadVao);
    }
}

