// ── Engine.java → cleanup() ───────────────────────────────────
public void cleanup() {

    // ── STEP 1: Unbind all active state before deletion ───────
    // Prevents driver use-after-free on sensitive implementations
    glUseProgram(0);
    glBindVertexArray(0);
    glBindBuffer(GL_ARRAY_BUFFER, 0);
    glBindBuffer(GL_ELEMENT_ARRAY_BUFFER, 0);
    glBindFramebuffer(GL_FRAMEBUFFER, 0);
    glBindTexture(GL_TEXTURE_2D, 0);

    // ── STEP 2: Delete GL objects — child before parent ───────

    // VAO first — references VBO/EBO, free before the buffers
    for (Mesh mesh : meshes)
        mesh.delete();          // → glDeleteVertexArrays + glDeleteBuffers

    // Textures — free before FBO color attachments
    for (Texture tex : textures)
        tex.delete();           // → glDeleteTextures

    // Framebuffer — deletes FBO, color texture, RBO, quad VAO/VBO
    if (framebuffer != null)
        framebuffer.delete();   // → glDeleteFramebuffers + attachments

    // Shader program — last GL object deleted
    shader.delete();            // → glDeleteProgram

    // ── STEP 3: Free any remaining native CPU memory ──────────

    // Free STB image buffers held past upload (if any)
    // if (rawPixelBuffer != null) STBImage.stbi_image_free(rawPixelBuffer);

    // Free MemoryUtil buffers (if memAlloc* was used instead of BufferUtils)
    // MemoryUtil.memFree(someNativeBuffer);

    // ── STEP 4: GLFW shutdown — after ALL GL calls ─────────────
    // GL calls are invalid after glfwDestroyWindow — do this last

    // Free all registered window callbacks before destroying window
    Callbacks.glfwFreeCallbacks(window);

    // Destroy window + OpenGL context
    glfwDestroyWindow(window);

    // Free error callback — after window destruction
    glfwSetErrorCallback(null).free();

    // Terminate GLFW — must be the very last GLFW call
    glfwTerminate();

    // Hint JVM GC after all native resources are freed
    System.gc();

    System.out.println("Engine shutdown complete.");
}

// ── Main entry point — full engine lifecycle ──────────────────
public static void main(String[] args) {
    Engine engine = new Engine();
    try {
        engine.init();        // Phases 1–7:  window, GL, shaders, mesh, textures
        engine.renderLoop();  // Phase  8–10: frame loop, depth/blend, FBO
    } finally {
        engine.cleanup();     // Phase 11:    always runs, even on exception
    }
}

