public class Engine {

    // ── GLFW ────────────────────────────────────────────────
    private long window;
    private static final int WIDTH  = 800;
    private static final int HEIGHT = 600;

    // ── Subsystems ──────────────────────────────────────────
    private ShaderProgram   shader;
    private Mesh            mesh;
    private Texture         texture;
    private Camera          camera;
    private Framebuffer     framebuffer;
    private UniformManager  uniforms;

    // ── Per-frame state ─────────────────────────────────────
    private final Matrix4f   model         = new Matrix4f();
    private final FloatBuffer matrixBuffer = BufferUtils.createFloatBuffer(16);

    // ════════════════════════════════════════════════════════
    // PHASE 1 + 2 — Window creation and GL state
    // ════════════════════════════════════════════════════════
    public void init() {

        // ── Phase 1: Window & Context Creation ──────────────
        GLFWErrorCallback.createPrint(System.err).set();
        if (!glfwInit()) throw new IllegalStateException("GLFW init failed");

        glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 3);
        glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 3);
        glfwWindowHint(GLFW_OPENGL_PROFILE, GLFW_OPENGL_CORE_PROFILE);
        glfwWindowHint(GLFW_VISIBLE,   GLFW_FALSE);
        glfwWindowHint(GLFW_RESIZABLE, GLFW_TRUE);

        window = glfwCreateWindow(WIDTH, HEIGHT, "MyEngine", NULL, NULL);
        if (window == NULL) throw new RuntimeException("Window creation failed");

        glfwSetKeyCallback(window, (win, key, scancode, action, mods) -> {
            if (key == GLFW_KEY_ESCAPE && action == GLFW_PRESS)
                glfwSetWindowShouldClose(win, true);
        });
        glfwSetFramebufferSizeCallback(window, (win, w, h) -> {
            glViewport(0, 0, w, h);
            camera.buildProjection((float) w / h);
        });

        GLFWVidMode vm = glfwGetVideoMode(glfwGetPrimaryMonitor());
        glfwSetWindowPos(window, (vm.width()-WIDTH)/2, (vm.height()-HEIGHT)/2);
        glfwMakeContextCurrent(window);
        glfwSwapInterval(1);
        glfwShowWindow(window);

        // ── Phase 2: OpenGL Context Initialization ───────────
        GL.createCapabilities();
        System.out.println("OpenGL : " + glGetString(GL_VERSION));
        System.out.println("GLSL   : " + glGetString(GL_SHADING_LANGUAGE_VERSION));

        glViewport(0, 0, WIDTH, HEIGHT);
        glClearColor(0.1f, 0.1f, 0.1f, 1.0f);
        glEnable(GL_DEPTH_TEST);
        glDepthFunc(GL_LESS);
        glEnable(GL_CULL_FACE);
        glCullFace(GL_BACK);
        glFrontFace(GL_CCW);
    }

    // ════════════════════════════════════════════════════════
    // PHASE 3-7 — Shaders, mesh, textures, camera, uniforms
    // ════════════════════════════════════════════════════════
    public void setup() {

        // ── Phase 3: Shader System ───────────────────────────
        shader   = new ShaderProgram("shaders/vertex.vert",
                                     "shaders/fragment.frag");
        uniforms = new UniformManager(shader.getProgramID());
        uniforms.cacheLocation("uModel");
        uniforms.cacheLocation("uView");
        uniforms.cacheLocation("uProjection");
        uniforms.cacheLocation("uTexture");
        uniforms.cacheLocation("uLightPos");
        uniforms.cacheLocation("uTime");
        uniforms.setInt("uTexture", 0); // sampler2D → unit 0

        // ── Phase 4: Vertex Buffer & Mesh Setup ──────────────
        float[] vertices = {
        //   x      y      z      u     v     nx    ny    nz
            -0.5f, -0.5f,  0.5f,  0f,   0f,   0f,   0f,   1f,
             0.5f, -0.5f,  0.5f,  1f,   0f,   0f,   0f,   1f,
             0.5f,  0.5f,  0.5f,  1f,   1f,   0f,   0f,   1f,
            -0.5f,  0.5f,  0.5f,  0f,   1f,   0f,   0f,   1f
        };
        int[] indices = { 0,1,2, 2,3,0 };
        mesh = new Mesh(vertices, indices);

        // ── Phase 5: Texture Loading & Binding ───────────────
        texture = new Texture("textures/diffuse.png");

        // ── Phase 6: Camera & Transformation Matrices ────────
        camera = new Camera(0.0f, 0.0f, 3.0f);
        camera.buildProjection((float) WIDTH / HEIGHT);

        // ── Phase 7: Uniform — upload projection once ────────
        shader.bind();
        uniforms.setMatrix4f("uProjection", camera.getProjectionMatrix());

        // ── Phase 10: Framebuffer setup ───────────────────────
        framebuffer = new Framebuffer(WIDTH, HEIGHT);
    }

    // ════════════════════════════════════════════════════════
    // PHASE 8-10 — Render loop, depth/blend, FBO
    // ════════════════════════════════════════════════════════
    public void renderLoop() {

        double lastFrameTime = glfwGetTime();

        while (!glfwWindowShouldClose(window)) {

            // ── Phase 8: Frame timing + input ────────────────
            double now       = glfwGetTime();
            float  deltaTime = (float)(now - lastFrameTime);
            lastFrameTime    = now;
            glfwPollEvents();
            camera.update(window, deltaTime);

            // ── Phase 10: Pass 1 — render scene into FBO ─────
            framebuffer.bindForRendering(); // binds FBO + clears

            // ── Phase 8: Bind shader ──────────────────────────
            shader.bind();

            // ── Phase 7: Upload per-frame uniforms ───────────
            uniforms.setMatrix4f("uView",     camera.getViewMatrix());
            uniforms.setVec3("uLightPos",     1.2f, 1.0f, 2.0f);
            uniforms.setFloat("uTime",        (float) now);

            // ── Phase 9: Opaque pass — full depth r/w ────────
            glDepthMask(true);
            glDisable(GL_BLEND);

            // ── Phase 6 + 7: Per-object model matrix + draw ──
            model.identity().translate(0f, 0f, 0f).rotate(
                (float) Math.toRadians(now * 30), 0f, 1f, 0f).scale(1f);
            uniforms.setMatrix4f("uModel", model);
            texture.bind(GL_TEXTURE0);
            mesh.draw(); // glBindVertexArray + glDrawElements

            // ── Phase 10: Pass 2 — post-process to screen ────
            framebuffer.drawToScreen(shader.getPostProgramID());

            // ── Phase 8: Present frame ────────────────────────
            glfwSwapBuffers(window);
        }
    }

    // ════════════════════════════════════════════════════════
    // PHASE 11 — Cleanup
    // ════════════════════════════════════════════════════════
    public void cleanup() {
        glUseProgram(0);
        glBindVertexArray(0);
        glBindFramebuffer(GL_FRAMEBUFFER, 0);

        mesh.delete();          // glDeleteVertexArrays + buffers
        texture.delete();       // glDeleteTextures
        framebuffer.delete();   // glDeleteFramebuffers + attachments
        shader.delete();        // glDeleteProgram

        Callbacks.glfwFreeCallbacks(window);
        glfwDestroyWindow(window);
        glfwSetErrorCallback(null).free();
        glfwTerminate();
        System.gc();
    }
}

